import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.D5wUhsuj.js";const c=JSON.parse('{"title":"MLOps","description":"","frontmatter":{},"headers":[],"relativePath":"mlops/index.md","filePath":"mlops/index.md","lastUpdated":1783543014000}'),l={name:"mlops/index.md"};function i(n,e,s,d,h,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="mlops" tabindex="-1">MLOps <a class="header-anchor" href="#mlops" aria-label="Permalink to &quot;MLOps&quot;">​</a></h1><p>MLOps in prokube covers the operational path from interactive model development to repeatable training, experiment tracking, model registry workflows, and serving endpoints.</p><p>Use <a href="./../labs/">Labs</a> for interactive work, then move repeatable or shared workloads into the MLOps services below.</p><h2 id="main-workflows" tabindex="-1">Main Workflows <a class="header-anchor" href="#main-workflows" aria-label="Permalink to &quot;Main Workflows&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Workflow</th><th>Use</th></tr></thead><tbody><tr><td><a href="./pipelines.html">Pipelines</a></td><td>Run reproducible, inspectable workflows with Kubeflow Pipelines. Use this when notebook work should become a cluster-executed workflow.</td></tr><tr><td><a href="./hyperparameter_tuning.html">Hparam Search</a></td><td>Run Katib experiments to compare parameter combinations and parallelize trials on cluster compute.</td></tr><tr><td><a href="./mlflow.html">MLflow</a></td><td>Track experiments, log artifacts, manage model registry entries, and issue credentials for notebooks, pipelines, and serving.</td></tr><tr><td><a href="./model_serving.html">Model Serving</a></td><td>Deploy trained models as KServe inference endpoints, including models from object storage or MLflow.</td></tr><tr><td><a href="./model_serving_autoscaling.html">Model Serving Autoscaling</a></td><td>Tune KServe autoscaling with KPA, HPA, and KEDA, including vLLM token-throughput metrics.</td></tr><tr><td><a href="./knative.html">Serverless</a></td><td>Run generic HTTP containers with Knative Serving when the workload is not a model-specific KServe deployment.</td></tr></tbody></table><h2 id="typical-flow" tabindex="-1">Typical Flow <a class="header-anchor" href="#typical-flow" aria-label="Permalink to &quot;Typical Flow&quot;">​</a></h2><ol><li>Develop code and inspect data in a <a href="./../labs/jupyterlab.html">JupyterLab</a>, <a href="./../labs/vscode.html">VS Code Lab</a>, or <a href="./../labs/rstudio.html">RStudio Lab</a>.</li><li>Track experiments and model artifacts in <a href="./mlflow.html">MLflow</a>.</li><li>Convert repeatable training or evaluation steps into <a href="./pipelines.html">Pipelines</a>.</li><li>Use <a href="./hyperparameter_tuning.html">Hparam Search</a> when parameters should be explored systematically across cluster resources.</li><li>Deploy the selected model through <a href="./model_serving.html">Model Serving</a>.</li></ol><h2 id="foundation" tabindex="-1">Foundation <a class="header-anchor" href="#foundation" aria-label="Permalink to &quot;Foundation&quot;">​</a></h2><p>MLOps workloads run on the shared prokube foundation: workspaces, Kubernetes namespaces, storage, identity, RBAC, and observability.</p><p>Start with these cross-cutting pages when you need platform behavior rather than tool-specific usage:</p><ul><li><a href="./../platform/workspaces.html">Workspaces</a></li><li><a href="./../platform/kubernetes.html">Kubernetes Resources</a></li><li><a href="./../platform/observability.html">Observability</a></li><li><a href="./../platform/api_keys.html">API Keys</a></li></ul>',11)])])}const f=t(l,[["render",i]]);export{c as __pageData,f as default};
